70	    const imageGenerationConfig = {
71	      ...(width ? { width } : {}),
72	      ...(height ? { height } : {}),
73	      ...(seed ? { seed } : {}),
74	      ...(n ? { numberOfImages: n } : {}),
75	      ...(providerOptions?.bedrock?.quality
