76	/**
77	 * Extracts a mapping from MCP approval request IDs to their corresponding tool call IDs
78	 * from the prompt. When an MCP tool requires approval, we generate a tool call ID to track
79	 * the pending approval in our system. When the user responds to the approval (and we
80	 * continue the conversation), we need to map the approval request ID back to our tool call ID
81	 * so that tool results reference the correct tool call.
82	 */
83	function extractApprovalRequestIdToToolCallIdMapping(
84	  prompt: LanguageModelV3Prompt,
85	): Record<string, string> {
86	  const mapping: Record<string, string> = {};
87	  for (const message of prompt) {
88	    if (message.role !== 'assistant') continue;
89	    for (const part of message.content) {
90	      if (part.type !== 'tool-call') continue;
91	      const approvalRequestId = part.providerOptions?.openai
92	        ?.approvalRequestId as string | undefined;
93	      if (approvalRequestId != null) {
94	        mapping[approvalRequestId] = part.toolCallId;
95	      }
96	    }
97	  }
98	  return mapping;
99	}
