43	  async doGenerate({
44	    prompt,
45	    n,
46	    size,
47	    aspectRatio,
48	    seed,
49	    providerOptions,
50	    headers,
51	    abortSignal,
52	    files,
53	    mask,
54	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
55	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
56	  > {
57	    const warnings: Array<SharedV3Warning> = [];
58	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
59	
60	    // Image editing mode - use OpenAI-compatible /images/edits endpoint
61	    if (files != null && files.length > 0) {
62	      const { value: response, responseHeaders } = await postFormDataToApi({
63	        url: this.getEditUrl(),
64	        headers: combineHeaders(this.config.headers(), headers),
65	        formData: convertToFormData<DeepInfraFormDataInput>(
66	          {
67	            model: this.modelId,
68	            prompt,
69	            image: await Promise.all(files.map(file => fileToBlob(file))),
70	            mask: mask != null ? await fileToBlob(mask) : undefined,
71	            n,
72	            size,
73	            ...(providerOptions.deepinfra ?? {}),
74	          },
75	          { useArrayBrackets: false },
76	        ),
77	        failedResponseHandler: createJsonErrorResponseHandler({
78	          errorSchema: deepInfraEditErrorSchema,
79	          errorToMessage: error => error.error?.message ?? 'Unknown error',
80	        }),
81	        successfulResponseHandler: createJsonResponseHandler(
82	          deepInfraEditResponseSchema,
83	        ),
84	        abortSignal,
85	        fetch: this.config.fetch,
86	      });
87	
88	      return {
89	        images: response.data.map(item => item.b64_json),
90	        warnings,
91	        response: {
92	          timestamp: currentDate,
93	          modelId: this.modelId,
94	          headers: responseHeaders,
95	        },
96	      };
97	    }
98	
99	    // Standard image generation mode
100	    // Some deepinfra models support size while others support aspect ratio.
101	    // Allow passing either and leave it up to the server to validate.
102	    const splitSize = size?.split('x');
103	    const { value: response, responseHeaders } = await postJsonToApi({
104	      url: `${this.config.baseURL}/${this.modelId}`,
105	      headers: combineHeaders(this.config.headers(), headers),
106	      body: {
107	        prompt,
108	        num_images: n,
109	        ...(aspectRatio && { aspect_ratio: aspectRatio }),
110	        ...(splitSize && { width: splitSize[0], height: splitSize[1] }),
111	        ...(seed != null && { seed }),
112	        ...(providerOptions.deepinfra ?? {}),
113	      },
114	      failedResponseHandler: createJsonErrorResponseHandler({
115	        errorSchema: deepInfraErrorSchema,
116	        errorToMessage: error => error.detail.error,
117	      }),
118	      successfulResponseHandler: createJsonResponseHandler(
119	        deepInfraImageResponseSchema,
120	      ),
121	      abortSignal,
122	      fetch: this.config.fetch,
123	    });
124	
125	    return {
126	      images: response.images.map(image =>
127	        image.replace(/^data:image\/\w+;base64,/, ''),
128	      ),
129	      warnings,
130	      response: {
131	        timestamp: currentDate,
132	        modelId: this.modelId,
133	        headers: responseHeaders,
134	      },
135	    };
136	  }
