138	  private getEditUrl(): string {
139	    // Use OpenAI-compatible endpoint for image editing
140	    // baseURL is typically https://api.deepinfra.com/v1/inference
141	    // We need to use https://api.deepinfra.com/v1/openai/images/edits
142	    const baseUrl = this.config.baseURL.replace('/inference', '/openai');
143	    return `${baseUrl}/images/edits`;
