48	  constructor(
49	    readonly modelId: string,
50	    private readonly config: LumaImageModelConfig,
51	  ) {}
52	
53	  async doGenerate({
54	    prompt,
55	    n,
56	    size,
57	    aspectRatio,
58	    seed,
59	    providerOptions,
60	    headers,
61	    abortSignal,
62	    files,
63	    mask,
64	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
