25	export type OpenAICompatibleImageModelConfig = {
26	  provider: string;
27	  headers: () => Record<string, string | undefined>;
28	  url: (options: { modelId: string; path: string }) => string;
29	  fetch?: FetchFunction;
30	  errorStructure?: ProviderErrorStructure<any>;
31	  _internal?: {
32	    currentDate?: () => Date;
33	  };
34	};
35	
36	export class OpenAICompatibleImageModel implements ImageModelV3 {
37	  readonly specificationVersion = 'v3';
38	  readonly maxImagesPerCall = 10;
39	
40	  get provider(): string {
41	    return this.config.provider;
42	  }
43	
44	  /**
45	   * The provider options key used to extract provider-specific options.
46	   */
47	  private get providerOptionsKey(): string {
48	    return this.config.provider.split('.')[0].trim();
49	  }
50	
51	  constructor(
52	    readonly modelId: OpenAICompatibleImageModelId,
53	    private readonly config: OpenAICompatibleImageModelConfig,
54	  ) {}
55	
56	  // TODO: deprecate non-camelCase keys and remove in future major version
57	  private getArgs(
58	    providerOptions: SharedV3ProviderOptions,
59	  ): Record<string, unknown> {
60	    return {
61	      ...providerOptions[this.providerOptionsKey],
62	      ...providerOptions[toCamelCase(this.providerOptionsKey)],
63	    };
64	  }
65	
66	  async doGenerate({
67	    prompt,
68	    n,
69	    size,
70	    aspectRatio,
71	    seed,
72	    providerOptions,
73	    headers,
74	    abortSignal,
75	    files,
76	    mask,
77	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
78	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
79	  > {
80	    const warnings: Array<SharedV3Warning> = [];
81	
82	    if (aspectRatio != null) {
83	      warnings.push({
84	        type: 'unsupported',
85	        feature: 'aspectRatio',
86	        details:
87	          'This model does not support aspect ratio. Use `size` instead.',
88	      });
89	    }
90	
91	    if (seed != null) {
92	      warnings.push({ type: 'unsupported', feature: 'seed' });
93	    }
94	
95	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
96	
97	    const args = this.getArgs(providerOptions);
98	
99	    // Image editing mode - use form data and /images/edits endpoint
100	    if (files != null && files.length > 0) {
101	      const { value: response, responseHeaders } = await postFormDataToApi({
102	        url: this.config.url({
103	          path: '/images/edits',
104	          modelId: this.modelId,
105	        }),
106	        headers: combineHeaders(this.config.headers(), headers),
107	        formData: convertToFormData<OpenAICompatibleFormDataInput>({
108	          model: this.modelId,
109	          prompt,
110	          image: await Promise.all(files.map(file => fileToBlob(file))),
111	          mask: mask != null ? await fileToBlob(mask) : undefined,
112	          n,
113	          size,
114	          ...args,
115	        }),
116	        failedResponseHandler: createJsonErrorResponseHandler(
117	          this.config.errorStructure ?? defaultOpenAICompatibleErrorStructure,
118	        ),
119	        successfulResponseHandler: createJsonResponseHandler(
120	          openaiCompatibleImageResponseSchema,
121	        ),
122	        abortSignal,
123	        fetch: this.config.fetch,
124	      });
125	
126	      return {
127	        images: response.data.map(item => item.b64_json),
128	        warnings,
129	        response: {
130	          timestamp: currentDate,
131	          modelId: this.modelId,
132	          headers: responseHeaders,
133	        },
134	      };
135	    }
136	
137	    // Standard image generation mode - use JSON and /images/generations endpoint
138	    const { value: response, responseHeaders } = await postJsonToApi({
139	      url: this.config.url({
140	        path: '/images/generations',
141	        modelId: this.modelId,
142	      }),
143	      headers: combineHeaders(this.config.headers(), headers),
144	      body: {
145	        model: this.modelId,
146	        prompt,
147	        n,
148	        size,
149	        ...args,
150	        response_format: 'b64_json',
151	      },
152	      failedResponseHandler: createJsonErrorResponseHandler(
153	        this.config.errorStructure ?? defaultOpenAICompatibleErrorStructure,
154	      ),
155	      successfulResponseHandler: createJsonResponseHandler(
156	        openaiCompatibleImageResponseSchema,
157	      ),
158	      abortSignal,
159	      fetch: this.config.fetch,
160	    });
161	
162	    return {
163	      images: response.data.map(item => item.b64_json),
164	      warnings,
165	      response: {
166	        timestamp: currentDate,
167	        modelId: this.modelId,
168	        headers: responseHeaders,
169	      },
170	    };
171	  }
172	}
173	
174	// minimal version of the schema, focussed on what is needed for the implementation
175	// this approach limits breakages when the API changes and increases efficiency
176	const openaiCompatibleImageResponseSchema = z.object({
177	  data: z.array(z.object({ b64_json: z.string() })),
178	});
179	
180	type OpenAICompatibleFormDataInput = {
181	  model: string;
182	  prompt: string | undefined;
183	  image: Blob | Blob[];
184	  mask?: Blob;
185	  n: number;
186	  size: `${number}x${number}` | undefined;
187	  [key: string]: unknown;
188	};
189	
190	async function fileToBlob(file: ImageModelV3File): Promise<Blob> {
191	  if (file.type === 'url') {
192	    return downloadBlob(file.url);
193	  }
194	
195	  const data =
196	    file.data instanceof Uint8Array
197	      ? file.data
198	      : convertBase64ToUint8Array(file.data);
199	
200	  return new Blob([data as BlobPart], { type: file.mediaType });
201	}
202	
203	function toCamelCase(str: string): string {
204	  return str.replace(/[_-]([a-z])/g, g => g[1].toUpperCase());
205	}
