  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  Resolvable,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export interface PixelArtImageSettings {
  // Custom settings for this provider (optional)
  customParam?: string;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    // Define max images per call based on model or settings
    return 4;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n = 1,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Handle unsupported features
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'This model does not support image editing',
      });
    }

    // Parse provider-specific options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    // Build request body
    const body = {
      model: this.modelId,
      prompt,
      n,
      size,
      aspectRatio,
      ...pixelartOptions,
    };

    // Make API call
    const { responseHeaders, value: response } = await postJsonToApi({
      url: `${this.config.baseURL}/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images, // array of base64 strings or Uint8Array
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.images.map(() => ({
            // Provider-specific metadata per image
          })),
        },
      },
    };
  }
}

// Schema for API response
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(z.string()), // array of base64 strings
    }),
  ),
);

// Schema for provider-specific options
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      quality: z.enum(['low', 'medium', 'high']).nullish(),
      style: z.string().nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;
```

---

### 6. **Provider Factory Pattern**

**File:** `/packages/openai/src/openai-provider.ts` and `/packages/replicate/src/replicate-provider.ts`

**For image-only provider:**

```typescript
import {
  NoSuchModelError,
  ProviderV3,
  ImageModelV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageSettings } from './pixelart-image-model';
import { VERSION } from './version';

export type PixelArtImageModelId =
  | 'pixelart-3.0'
  | 'pixelart-2.0'
  | (string & {});

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

export interface PixelArtProviderSettings {
  /**
   * API key for authentication
   * Defaults to PIXELART_API_KEY environment variable
   */
  apiKey?: string;

  /**
   * Base URL for API calls
   */
  baseURL?: string;

  /**
   * Custom headers
   */
  headers?: Record<string, string | undefined>;

  /**
   * Custom fetch implementation
   */
  fetch?: FetchFunction;
}

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? 'https://api.pixelart.com/v1';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ) =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,

    // Throw errors for unsupported model types
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },

    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
  };
}

/**
 * Default PixelArt provider instance
 */
export const pixelart = createPixelArt();
```

