import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { PixelArtImageSettings } from './pixelart-image-settings';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'This model does not support the `seed` option.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'This model does not support image editing with input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'This model does not support mask-based image editing.',
      });
    }

    // Parse and validate provider options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    // Use size from provider options, then from settings, then from call options
    const resolvedSize =
      pixelartOptions?.size ?? this.settings.size ?? size ?? undefined;
    if (resolvedSize != null) {
      body.size = resolvedSize;
    }

    // Use style from provider options, then from settings
    const resolvedStyle =
      pixelartOptions?.style ?? this.settings.style ?? undefined;
    if (resolvedStyle != null) {
      body.style = resolvedStyle;
    }

    // Use pixelDensity from provider options, then from settings
    const resolvedPixelDensity =
      pixelartOptions?.pixelDensity ?? this.settings.pixelDensity ?? undefined;
    if (resolvedPixelDensity != null) {
      body.pixel_density = resolvedPixelDensity;
    }

    const { responseHeaders, value: response } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: (error: PixelArtErrorData) =>
          error.error?.message ?? 'Unknown error',
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(image => image.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focussed on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      type: z.string().nullish(),
      code: z.string().nullish(),
    })
    .nullish(),
});

export type PixelArtErrorData = z.infer<typeof pixelartErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style to apply to the generated image.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density of the generated image. Higher values produce more
       * detailed pixel art.
       */
      pixelDensity: z.number().nullish(),

      /**
       * The size of the generated image (e.g., '256x256', '512x512').
       */
      size: z.string().nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

